
def get_type2cluster_dict(type2cluster_file):
    with open(type2cluster_file, 'r') as type2cluster:
        type2cluster_dict = {}
        clu_dict = {}
        clu_dict_index = 0
        for line in type2cluster:
            line = line.strip()
            if not line:
                continue
            type2cluster_list = line.split('	')
            if type2cluster_list[1] not in clu_dict:
                clu_dict[type2cluster_list[1]] = clu_dict_index
                clu_dict_index = clu_dict_index + 1
            if type2cluster_list[0] not in type2cluster_dict:
                type2cluster_dict[type2cluster_list[0]] = [type2cluster_list[1]]
            else:
                type2cluster_dict[type2cluster_list[0]] = type2cluster_dict[type2cluster_list[0]] + \
                                                          [type2cluster_list[1]]
        return clu_dict, type2cluster_dict

def get_type2cluster_index_dict(type_file, clu_dict, type2cluster_dict):
    with open(type_file, 'r') as type:
        type_dict = {}
        for line in type:
            line = line.strip()
            if not line:
                continue
            type_list = line.split('	')
            if type_list[0] not in type_dict:
                type_dict[type_list[0] + '/'] = int(type_list[1])
        type2cluster_dict_index = {}
        for type2cluster_dict_each in type2cluster_dict:
            type2cluster_dict_index_clusteridx = []
            for type2cluster_dict_each_cluster in type2cluster_dict[type2cluster_dict_each]:
                type2cluster_dict_index_clusteridx.append(clu_dict[type2cluster_dict_each_cluster])
            if type_dict[type2cluster_dict_each] not in type2cluster_dict_index:
                type2cluster_dict_index[type_dict[type2cluster_dict_each]] = type2cluster_dict_index_clusteridx
            else:
                type2cluster_dict_index[type_dict[type2cluster_dict_each]] = \
                    type2cluster_dict_index[type_dict[type2cluster_dict_each]] + type2cluster_dict_index_clusteridx
        return type2cluster_dict_index

def output_clu_dict(clu_dict, output_file):
    with open(output_file, 'w') as f:
        for clu_dict_each in clu_dict:
            f.writelines([clu_dict_each, '\t', str(clu_dict[clu_dict_each]), '\n'])

def get_cluster_index(type2cluster_dict_index, cluster_len):
    cluster_index = []
    for index_num in range(cluster_len):
        tmp_list = []
        for type2cluster_dict_index_each in type2cluster_dict_index:
            for cluster_list_num in type2cluster_dict_index[type2cluster_dict_index_each]:
                if cluster_list_num == index_num:
                    tmp_list.append(type2cluster_dict_index_each)
        cluster_index.append(tmp_list)
    return cluster_index

