def get_origin_type2cluster_dict(type2cluster_file, clusters_file):
    with open(clusters_file, 'r') as clusters:
        clu_dict = {}
        for line in clusters:
            line = line.strip()
            if not line:
                continue
            clu_list = line.split('	')
            if not clu_list[0].startswith('/'):
                clu_list[0] = '/' + clu_list[0]
            clu_dict[clu_list[0] + '/'] = int(clu_list[1])

    with open(type2cluster_file, 'r') as type2cluster:
        type2cluster_dict = {}
        for line in type2cluster:
            line = line.strip()
            if not line:
                continue
            type2cluster_list = line.split('	')
            if type2cluster_list[0] not in type2cluster_dict:
                type2cluster_dict[type2cluster_list[0]] = [type2cluster_list[1]]
            else:
                type2cluster_dict[type2cluster_list[0]] = type2cluster_dict[type2cluster_list[0]] + \
                                                          [type2cluster_list[1]]
        return clu_dict, type2cluster_dict

